/// <summary>
/// Extension of the <c>VendTable</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(VendTable))]
final class VendTable_Table_ETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Method to regenerate the numeric sequence of the table.
/// </summary>
/// <returns>VendAccount.</returns>
public VendAccount ETGSPAINGenerateVendAccount()
{
    VendAccount ret;
    str         range;
    VendTable   vendTable;

    ret += "V";
    ret += "_";
    ret += this.VendGroup;
    ret += "_";
    ret += this.DataAreaId;
    ret += "_";
    ret += this.ETGSPAINSalesPurchPartyCountry;

    range = strFmt("%1*", ret);

    select firstonly count(RecId) from vendTable
        order by AccountNum desc
        where vendTable.AccountNum like range
            && vendTable.AccountNum != ret;

    System.Int64    numberOfRecords     = vendTable.RecId + 1;
    String10        numberOfRecordsStr  = numberOfRecords.ToString("D3");

    ret += strFmt("_%1", numberOfRecordsStr);        

    return strUpr(ret);
}
